/* ════════════════════════════════════════════════════════════════
   rotinas.js v5.0 — Aba Rotinas Semanais
   ────────────────────────────────────────────────────────────────
   LÓGICA CORRETA:
   • Turmas no topo = lista de turmas DISPONÍVEIS para a rotina
   • Cada célula tem seu próprio select de componente + select de turma
   • Estrutura da célula: { disc, turma, atv }
   • PDF: turma vem de cada célula individualmente
   • PDF: print funciona com estrutura correta
   A.V. Leitura+
════════════════════════════════════════════════════════════════ */

var rotLista              = [];
var rotIdAtual            = null;
var rotProxLocalId        = 1;
var _rotAtualVisualizando = null;

/* ── Componentes ─────────────────────────────────────────────── */
var ROT_DISCIPLINAS = [
    "","PORTUGUÊS","MATEMÁTICA","CIÊNCIAS","GEOGRAFIA","HISTÓRIA",
    "ARTE","EDUCAÇÃO FÍSICA","ENSINO RELIGIOSO",
    "EDUCAÇÃO FINANCEIRA","EDUCAÇÃO AMBIENTAL"
];

/* ── Horários ────────────────────────────────────────────────── */
var ROT_GRADE_NORMAL = [
    { key:"h1",    h:"7:10 – 7:55",   label:"1º", tipo:"aula"   },
    { key:"h2",    h:"7:55 – 8:40",   label:"2º", tipo:"aula"   },
    { key:"h3",    h:"8:40 – 9:25",   label:"3º", tipo:"aula"   },
    { key:"int",   h:"9:25 – 9:35",   label:"Intervalo", tipo:"especial", dur:"10 min" },
    { key:"h4",    h:"9:35 – 10:20",  label:"4º", tipo:"aula"   },
    { key:"h5",    h:"10:20 – 11:05", label:"5º", tipo:"aula"   },
    { key:"saida", h:"11:05",         label:"Saída", tipo:"saida" }
];
var ROT_GRADE_SEXTA = [
    { key:"h1",    h:"7:10 – 7:55",  label:"1º", tipo:"aula"    },
    { key:"h2",    h:"7:55 – 8:40",  label:"2º", tipo:"aula"    },
    { key:"int",   h:"8:40 – 9:00",  label:"Intervalo", tipo:"especial", dur:"20 min" },
    { key:"h3",    h:"9:00 – 9:45",  label:"3º", tipo:"aula"    },
    { key:"h4",    h:"9:45 – 10:30", label:"4º", tipo:"aula"    },
    { key:"saida", h:"10:30",        label:"Saída", tipo:"saida" }
];
var DIAS = [
    { nome:"Segunda-feira", abrev:"Seg", col:0, sexta:false },
    { nome:"Terça-feira",   abrev:"Ter", col:1, sexta:false },
    { nome:"Quarta-feira",  abrev:"Qua", col:2, sexta:false },
    { nome:"Quinta-feira",  abrev:"Qui", col:3, sexta:false },
    { nome:"Sexta-feira",   abrev:"Sex", col:4, sexta:true  }
];

/* ════════════════════════════════════════════════════════════════
   UTILITÁRIOS DE TURMAS
════════════════════════════════════════════════════════════════ */
function rotNormalizarTurmas(val) {
    if (!val) return [];
    if (Array.isArray(val)) return val.filter(Boolean);
    if (typeof val === "string") return [val].filter(Boolean);
    return [];
}

function rotOrdenarTurmas(arr) {
    return arr.slice().sort(function(a, b) {
        var na = parseInt((a.match(/\d+/) || [0])[0], 10);
        var nb = parseInt((b.match(/\d+/) || [0])[0], 10);
        if (na !== nb) return na - nb;
        var la = (a.match(/[A-Za-z]+$/) || [""])[0].toUpperCase();
        var lb = (b.match(/[A-Za-z]+$/) || [""])[0].toUpperCase();
        if (la !== lb) return la < lb ? -1 : 1;
        return a.localeCompare(b, "pt-BR");
    });
}

function rotTurmasTexto(turmas) {
    var arr = rotOrdenarTurmas(rotNormalizarTurmas(turmas));
    return arr.join(" • ") || "–";
}

function rotTurmasBadges(turmas, small) {
    var arr = rotOrdenarTurmas(rotNormalizarTurmas(turmas));
    if (!arr.length) return "<span style='color:#94a3b8'>–</span>";
    return arr.map(function(t) {
        return "<span class='rot-turma-badge" + (small ? " rot-turma-badge-sm" : "") + "'>" + _esc(t) + "</span>";
    }).join("");
}

/* ── Utilitários gerais ─────────────────────────────────────── */
function normalizarCelula(val) {
    if (!val) return { disc:"", turma:"", atv:"" };
    if (typeof val === "string") return { disc:"", turma:"", atv:val };
    return { disc:val.disc||"", turma:val.turma||"", atv:val.atv||"" };
}

function getCelula(celulas, rowKey, colIdx) {
    if (!celulas) return { disc:"", turma:"", atv:"" };
    var key = rowKey+"_"+colIdx;
    if (key === "__turmas_arr") return { disc:"", turma:"", atv:"" };
    var val = celulas[key];
    if (val !== undefined) return normalizarCelula(val);
    var li = ROT_GRADE_NORMAL.findIndex(function(h){ return h.key===rowKey; });
    if (li>=0) { val = celulas[li+"_"+colIdx]; if (val!==undefined) return normalizarCelula(val); }
    return { disc:"", turma:"", atv:"" };
}

function _esc(s){ if(!s)return""; return String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;"); }
/* getNomeEscola removida deste arquivo — função centralizada em app.js.
   Lá ela usa sysGetConfig() em vez de ler localStorage diretamente. */
function formatarDataBr(iso) {
    if (!iso) return ""; var p = iso.split("-");
    return p.length===3 ? p[2]+"/"+p[1]+"/"+p[0] : iso;
}

/* ════════════════════════════════════════════════════════════════
   PERMISSÕES
════════════════════════════════════════════════════════════════ */
function rotGetRole() {
    return typeof getUserRole === "function" ? getUserRole() : (function(){
        var u = getUsuarioLogado(); return u ? (u.cargo||u.role||"").toLowerCase() : "";
    })();
}
function rotGetNomeLogado() { var u = getUsuarioLogado(); return u ? (u.nome||"") : ""; }
function rotPodeVerRotina(r) {
    var role = rotGetRole();

    /* Administrador: sempre vê tudo */
    if (role === "administrador" || role === "admin") return true;

    /* Diretores e Supervisores: dependem da permissão global
       permissoes.visualizar_rotinas_gestao (padrão: true para manter
       o comportamento original do sistema) */
    if (role === "supervisora" || role === "supervisor"
        || role === "diretor"  || role === "diretora") {
        var perm = window._permissoes
            ? window._permissoes.visualizar_rotinas_gestao
            : (typeof permGetPerm === "function"
                ? permGetPerm("visualizar_rotinas_gestao", true)
                : true);
        if (perm) return true;
        /* Permissão desativada: gestão só vê as próprias */
        var nL = rotGetNomeLogado().toLowerCase().trim();
        var pR = (r.professor || "").toLowerCase().trim();
        return nL && pR && nL === pR;
    }

    /* Professor e demais perfis: só as próprias rotinas */
    var nL = rotGetNomeLogado().toLowerCase().trim();
    var pR = (r.professor || "").toLowerCase().trim();
    return nL && pR && nL === pR;
}
function rotPodeEditarRotina(r) {
    if (typeof podeEditarRotina === "function") return podeEditarRotina(r);
    var role = rotGetRole();
    if (role==="administrador"||role==="admin") return true;
    var nL = rotGetNomeLogado().toLowerCase().trim();
    var pR = (r.professor||"").toLowerCase().trim();
    return nL && pR && nL === pR;
}
function rotPodeDeletarRotina(r) { return rotPodeEditarRotina(r); }

/* ════════════════════════════════════════════════════════════════
   INICIALIZAÇÃO
════════════════════════════════════════════════════════════════ */
async function rotIniciar() {
    rotPopularTurmas();
    rotPreencherProfessorAuto();
    rotGerarTabela();
    await rotCarregarLista();
}

/* ────────────────────────────────────────────────────────────────
   PAINEL DE TURMAS DISPONÍVEIS (checkboxes no topo)
   Função: define quais turmas ficam disponíveis nos selects das células
   NÃO replica automaticamente nas células
──────────────────────────────────────────────────────────────── */
function rotPopularTurmas() {
    var container = document.getElementById("rot-turmas-container");
    if (!container) return;
    container.innerHTML = "";
    var turmas = getTurmasVisiveis(); /* turmas ocultas não aparecem nas rotinas para roles sem permissão */
    turmas.forEach(function(t) {
        var nome  = (typeof t==="object") ? t.nome  : t;
        var id = "rot-chk-" + nome.replace(/[\s"']/g,"_");
        var div = document.createElement("label");
        div.className = "rot-turma-check-item";
        div.innerHTML = "<input type='checkbox' id='" + id + "' value='" + _esc(nome) + "'>"
                      + "<span>" + _esc(nome.toUpperCase()) + "</span>";
        container.appendChild(div);
    });
}

/* Retorna array das turmas disponíveis (marcadas nos checkboxes) */
function rotGetTurmasDisponiveis() {
    var container = document.getElementById("rot-turmas-container");
    if (!container) return [];
    var checks = container.querySelectorAll("input[type='checkbox']:checked");
    var arr = [];
    checks.forEach(function(c){ arr.push(c.value); });
    return rotOrdenarTurmas(arr);
}

/* Atualiza o preview de badges e rebuild dos selects de turma nas células */
function rotAtualizarBadgesTurmas() {
    var preview = document.getElementById("rot-turmas-preview");
    var selecionadas = rotGetTurmasDisponiveis();
    if (preview) {
        if (selecionadas.length === 0) {
            preview.innerHTML = "<span style='color:#94a3b8;font-size:11px'>Nenhuma turma selecionada</span>";
        } else {
            preview.innerHTML = rotTurmasBadges(selecionadas, false);
        }
    }
    /* Rebuild dos selects de turma nas células para refletir opções disponíveis */
    _rotAtualizarSelectsTurma();
    var turmasTexto = selecionadas.length ? selecionadas.join(" • ") : "Nova Rotina";
    var prof = document.getElementById("rot-professor");
    rotAtualizarHeader(turmasTexto, prof ? prof.value : "");
}

/* Reconstrói APENAS as options dos selects de turma em cada célula */
function _rotAtualizarSelectsTurma() {
    var disponiveis = rotGetTurmasDisponiveis();
    document.querySelectorAll(".rot-sel-turma").forEach(function(sel) {
        var valorAtual = sel.value;
        sel.innerHTML = "<option value=''>— Turma —</option>"
            + disponiveis.map(function(t){
                var sel2 = (t===valorAtual) ? " selected" : "";
                return "<option value='" + _esc(t) + "'" + sel2 + ">" + _esc(t) + "</option>";
            }).join("");
        /* Restaura o valor se ainda disponível */
        if (valorAtual && disponiveis.includes(valorAtual)) sel.value = valorAtual;
    });
}

function rotSetTurmasSelecionadas(turmas) {
    var container = document.getElementById("rot-turmas-container");
    if (!container) return;
    var arr = rotNormalizarTurmas(turmas);
    container.querySelectorAll("input[type='checkbox']").forEach(function(c){
        c.checked = arr.indexOf(c.value) >= 0;
    });
    rotAtualizarBadgesTurmas();
}

function rotPreencherProfessorAuto() {
    var inp = document.getElementById("rot-professor");
    if (!inp) return;
    if (!inp.value || (!rotIdAtual && !inp.dataset.manual)) {
        var u = getUsuarioLogado(); if (u && u.nome) inp.value = u.nome;
    }
}

/* ════════════════════════════════════════════════════════════════
   GRADE v5 — select de componente + select de turma por célula
════════════════════════════════════════════════════════════════ */

function _buildSelectDisc(chave, valorAtual) {
    var opts = ROT_DISCIPLINAS.map(function(d) {
        var sel = (d===valorAtual) ? " selected" : "";
        return "<option value='"+d+"'"+sel+">"+(d||"— Componente —")+"</option>";
    }).join("");
    return "<select class='rot-sel-disc' data-key='"+chave+"' data-field='disc'>"+opts+"</select>";
}

/* Select de turma individual por célula */
function _buildSelectTurma(chave, valorAtual) {
    var disponiveis = rotGetTurmasDisponiveis();
    var opts = "<option value=''>— Turma —</option>"
        + disponiveis.map(function(t){
            var sel = (t===valorAtual) ? " selected" : "";
            return "<option value='"+_esc(t)+"'"+sel+">"+_esc(t)+"</option>";
        }).join("");
    return "<select class='rot-sel-turma' data-key='"+chave+"' data-field='turma'>"+opts+"</select>";
}

function _buildCelulaSexta(slot, celulas) {
    var COL_SEXTA = 4;
    if (slot.tipo === "especial") {
        return "<div class='rot-slot-especial rot-slot-int'>"
             + "☕ <b>Intervalo</b> — "+slot.dur
             + "<div style='font-size:9px;opacity:.7;margin-top:1px'>"+slot.h+"</div></div>";
    }
    if (slot.tipo === "saida") {
        return "<div class='rot-slot-especial rot-slot-saida'>🏠 <b>Saída</b> — "+slot.h+"</div>";
    }
    /* ── label sem º duplicado: slot.label já é "1º" ── */
    var cel   = celulas ? getCelula(celulas, slot.key, COL_SEXTA) : {disc:"",turma:"",atv:""};
    var chave = slot.key+"_"+COL_SEXTA;
    return "<div class='rot-slot-sexta'>"
         + "<div class='rot-slot-sexta-h'>"+slot.label+" · "+slot.h+"</div>"
         + "<div class='rot-cell-header-row'>"
         + _buildSelectDisc(chave, cel.disc)
         + _buildSelectTurma(chave, cel.turma)
         + "</div>"
         + "<textarea class='rot-inp-atv' data-key='"+chave+"' data-field='atv'"
         + " placeholder='Atividade...' rows='2'>"+_esc(cel.atv)+"</textarea>"
         + "</div>";
}

function rotGerarTabela(celulas) {
    var tbody = document.getElementById("rot-tbody");
    if (!tbody) return;
    var html = "";
    var nLinhas = ROT_GRADE_NORMAL.length;

    ROT_GRADE_NORMAL.forEach(function(slot, rowIdx) {
        html += "<tr>";

        /* ── Coluna horário: círculo + hora abaixo — SEM º adicional ── */
        var clsH = slot.tipo==="especial" ? " rot-td-horario-esp"
                 : slot.tipo==="saida"    ? " rot-td-horario-saida" : "";

        if (slot.tipo==="especial") {
            html += "<td class='rot-td-horario"+clsH+"'>"
                 + "<div class='rot-hr-circle-wrap'>"
                 + "<div class='rot-hr-label-esp'>Int.</div>"
                 + "<div class='rot-hr-time-v'>"+slot.h+"</div>"
                 + "<div class='rot-hr-time-v'>"+slot.dur+"</div>"
                 + "</div></td>";
        } else if (slot.tipo==="saida") {
            html += "<td class='rot-td-horario"+clsH+"'>"
                 + "<div class='rot-hr-circle-wrap'>"
                 + "<div class='rot-hr-label-esp'>Saída</div>"
                 + "<div class='rot-hr-time-v'>"+slot.h+"</div>"
                 + "</div></td>";
        } else {
            /* slot.label já contém "1º" — não adicionar º novamente */
            html += "<td class='rot-td-horario"+clsH+"'>"
                 + "<div class='rot-hr-circle-wrap'>"
                 + "<div class='rot-hr-circle'>"+slot.label+"</div>"
                 + "<div class='rot-hr-time-v'>"+slot.h+"</div>"
                 + "</div></td>";
        }

        /* ── Colunas SEG–QUI: select componente + select turma + textarea ── */
        DIAS.filter(function(d){ return !d.sexta; }).forEach(function(dia) {
            if (slot.tipo === "especial") {
                html += "<td class='rot-td-intervalo'>☕ "+slot.h+" <span class='rot-bloco-dur'>"+slot.dur+"</span></td>";
            } else if (slot.tipo === "saida") {
                html += "<td class='rot-td-saida'>🏠 "+slot.h+"</td>";
            } else {
                var cel   = celulas ? getCelula(celulas, slot.key, dia.col) : {disc:"",turma:"",atv:""};
                var chave = slot.key+"_"+dia.col;
                html += "<td class='rot-td-celula'>"
                     + "<div class='rot-cell-header-row'>"
                     + _buildSelectDisc(chave, cel.disc)
                     + _buildSelectTurma(chave, cel.turma)
                     + "</div>"
                     + "<textarea class='rot-inp-atv' data-key='"+chave+"' data-field='atv'"
                     + " placeholder='Atividade / conteúdo...' rows='3'>"+_esc(cel.atv)+"</textarea>"
                     + "</td>";
            }
        });

        /* Sexta: rowspan na 1ª linha */
        if (rowIdx === 0) {
            html += "<td class='rot-td-sexta-full' rowspan='"+nLinhas+"'>";
            ROT_GRADE_SEXTA.forEach(function(s) { html += _buildCelulaSexta(s, celulas); });
            html += "</td>";
        }

        html += "</tr>";
    });

    tbody.innerHTML = html;
}

function rotColetarCelulas() {
    var mapa = {};
    document.querySelectorAll("#rot-tbody [data-key]").forEach(function(el) {
        var key=el.dataset.key, field=el.dataset.field;
        if (!key||key==="__turmas_arr") return;
        if (!mapa[key]) mapa[key]={disc:"",turma:"",atv:""};
        mapa[key][field] = (el.tagName==="SELECT") ? el.value : (el.value||"");
    });
    Object.keys(mapa).forEach(function(k){
        if(!mapa[k].disc&&!mapa[k].turma&&!mapa[k].atv) delete mapa[k];
    });
    return mapa;
}

/* ════════════════════════════════════════════════════════════════
   CARREGAR / SALVAR LISTA
════════════════════════════════════════════════════════════════ */
async function rotCarregarLista() {
    var dados = await sbBuscarRotinas();
    if (dados && dados.length>=0) {
        rotLista = dados.map(function(r) {
            var cel = r.celulas;
            if (typeof cel==="string") { try { cel=JSON.parse(cel); } catch(e){ cel={}; } }
            /* Compatibilidade retroativa: turma string → array */
            var turmas = rotNormalizarTurmas(r.turmas_arr || r.turma || (r.turmas ? r.turmas.nome : ""));
            return { id:r.id, turmas:turmas, turma:turmas[0]||"", professor:r.professor||"",
                     dataIni:r.data_ini||"", dataFim:r.data_fim||"", celulas:cel||{}, criadoEm:r.criado_em||"" };
        });
    } else {
        var local = localStorage.getItem("rotinas_lista");
        var raw = local ? JSON.parse(local) : [];
        rotLista = raw.map(function(r) {
            var turmas = rotNormalizarTurmas(r.turmas||r.turma);
            return Object.assign({},r,{turmas:turmas,turma:turmas[0]||""});
        });
    }
    rotRenderizarLista();
}

function rotSalvarLocal() { localStorage.setItem("rotinas_lista", JSON.stringify(rotLista)); }

/* ════════════════════════════════════════════════════════════════
   RENDERIZAR LISTA LATERAL
════════════════════════════════════════════════════════════════ */
function rotRenderizarLista() {
    var busca = (document.getElementById("rot-busca").value||"").toLowerCase();
    var cont  = document.getElementById("rot-lista");
    var lista = rotLista.filter(function(r) {
        if (!rotPodeVerRotina(r)) return false;
        var txt = rotTurmasTexto(r.turmas).toLowerCase();
        return !busca || txt.includes(busca) || (r.professor||"").toLowerCase().includes(busca);
    });
    if (lista.length===0) {
        cont.innerHTML = "<div class='rot-vazia'><i class='fas fa-calendar-plus'></i>Nenhuma rotina<br>Crie sua primeira!</div>";
        return;
    }
    cont.innerHTML = lista.map(function(r) {
        var periodo = r.dataIni ? formatarDataBr(r.dataIni)+(r.dataFim?" a "+formatarDataBr(r.dataFim):"") : "Sem período";
        var ativo   = String(r.id)===String(rotIdAtual) ? " active" : "";
        var podeEditar  = rotPodeEditarRotina(r);
        var podeDeletar = rotPodeDeletarRotina(r);
        var btnEditar = podeEditar
            ? "<button class='rot-btn-viz' onclick='rotEditarItem(\""+r.id+"\")'><i class='fas fa-pen'></i></button>"
            : "<button class='rot-btn-viz' disabled style='opacity:.35;cursor:not-allowed'><i class='fas fa-pen'></i></button>";
        var btnDeletar = podeDeletar
            ? "<button class='rot-btn-del' onclick='rotDeletar(\""+r.id+"\")'><i class='fas fa-trash'></i></button>" : "";
        return "<div class='rot-item"+ativo+"'>"
            + "<div class='rot-item-titulo' onclick='rotVisualizarId(\""+r.id+"\")'>" + rotTurmasBadges(r.turmas,true) + "</div>"
            + "<div class='rot-item-meta'><span>👤 "+(r.professor||"–")+"</span><span>📅 "+periodo+"</span></div>"
            + "<div class='rot-item-actions'>"
            + "<button class='rot-btn-viz' onclick='rotVisualizarId(\""+r.id+"\")'><i class='fas fa-eye'></i></button>"
            + btnEditar + btnDeletar
            + "</div></div>";
    }).join("");
}

function rotFiltrarLista() { rotRenderizarLista(); }

/* ════════════════════════════════════════════════════════════════
   CARREGAR NO EDITOR (editar)
════════════════════════════════════════════════════════════════ */
function rotEditarItem(id) {
    var r = rotLista.find(function(x){ return String(x.id)===String(id); });
    if (!r) return;
    if (typeof alPodeEditar==="function" && !alPodeEditar()) {
        var sel = typeof alGetAnoSelecionado==="function" ? alGetAnoSelecionado() : null;
        mostrarModalAviso("Modo histórico","Não é possível editar rotinas do Ano Letivo "+(sel?sel.ano:"anterior")+".");
        return;
    }
    if (!rotPodeEditarRotina(r)) { mostrarModalAviso("Sem permissão","Você não tem permissão para editar esta rotina."); return; }
    rotIdAtual = r.id;
    /* Marca as turmas que aparecem nas células como disponíveis */
    var turmasCelulas = _rotExtrairTurmasDasCelulas(r.celulas);
    var turmasDisp = rotNormalizarTurmas(r.turmas||r.turma);
    /* União: turmas da rotina + turmas das células */
    var todasTurmas = rotOrdenarTurmas([...new Set([...turmasDisp,...turmasCelulas])]);
    rotSetTurmasSelecionadas(todasTurmas);
    document.getElementById("rot-professor").value = r.professor||"";
    document.getElementById("rot-data-ini").value  = r.dataIni  ||"";
    document.getElementById("rot-data-fim").value  = r.dataFim  ||"";
    rotGerarTabela(r.celulas);
    rotAtualizarBadgesTurmas();
    rotAtualizarHeader(rotTurmasTexto(todasTurmas), r.professor);
    rotRenderizarLista();
    rotFecharModal();
}
function rotCarregarItem(id) { rotEditarItem(id); }

/* Extrai todas as turmas presentes nas células (campo turma de cada célula) */
function _rotExtrairTurmasDasCelulas(celulas) {
    if (!celulas) return [];
    var set = {};
    Object.values(celulas).forEach(function(v) {
        if (v && typeof v==="object" && v.turma) set[v.turma]=true;
    });
    return Object.keys(set);
}

function rotAtualizarHeader(turmasTexto, professor) {
    var t = document.getElementById("rot-titulo-header");
    var s = document.getElementById("rot-sub-header");
    if (t) t.innerText = turmasTexto && turmasTexto!=="–" ? "Rotina — "+turmasTexto : "Nova Rotina Semanal";
    if (s) s.innerText = professor ? "Prof.(a) "+professor : "Preencha as atividades de cada horário";
}

/* ════════════════════════════════════════════════════════════════
   SALVAR / NOVA / LIMPAR / DELETAR
════════════════════════════════════════════════════════════════ */
async function rotSalvar() {
    if (typeof alPodeEditar==="function" && !alPodeEditar()) {
        var sel = typeof alGetAnoSelecionado==="function" ? alGetAnoSelecionado() : null;
        mostrarModalAviso("Modo histórico","Não é possível salvar rotinas no Ano Letivo "+(sel?sel.ano:"anterior")+".");
        return;
    }
    var turmasDisp = rotGetTurmasDisponiveis();
    var professor  = document.getElementById("rot-professor").value.trim();
    var dataIni    = document.getElementById("rot-data-ini").value;
    var dataFim    = document.getElementById("rot-data-fim").value;
    var celulas    = rotColetarCelulas();
    if (!turmasDisp.length) { mostrarModalAviso("Atenção","Selecione pelo menos uma turma disponível."); return; }

    var rotina = {
        id:        rotIdAtual || ("local_"+rotProxLocalId++),
        turmas:    turmasDisp,
        turma:     turmasDisp[0]||"",
        professor: professor,
        dataIni:   dataIni,
        dataFim:   dataFim,
        celulas:   celulas
    };

    var salvo = await sbSalvarRotina(rotina);
    if (salvo) rotina.id = salvo.id;

    var idx = rotLista.findIndex(function(x){ return String(x.id)===String(rotina.id); });
    if (idx>=0) rotLista[idx]=rotina; else rotLista.unshift(rotina);
    rotIdAtual = rotina.id;
    rotSalvarLocal();
    rotRenderizarLista();
    rotAtualizarHeader(rotTurmasTexto(turmasDisp), professor);
    mostrarModalAviso("Salvo!","Rotina salva com sucesso.");
}

function rotNova() {
    rotIdAtual = null;
    rotLimpar();
    rotPreencherProfessorAuto();
    var container = document.getElementById("rot-turmas-container");
    if (container) container.querySelectorAll("input[type='checkbox']").forEach(function(c){ c.checked=false; });
    rotAtualizarBadgesTurmas();
    rotRenderizarLista();
    rotAtualizarHeader("","");
}

function rotLimpar() {
    document.getElementById("rot-data-ini").value = "";
    document.getElementById("rot-data-fim").value = "";
    document.querySelectorAll("#rot-tbody [data-key]").forEach(function(el){ el.value=""; });
}

function rotDeletar(id) {
    var r = rotLista.find(function(x){ return String(x.id)===String(id); });
    if (!r) return;
    if (typeof alPodeEditar==="function" && !alPodeEditar()) {
        var selD = typeof alGetAnoSelecionado==="function" ? alGetAnoSelecionado() : null;
        mostrarModalAviso("Modo histórico","Não é possível excluir rotinas do Ano Letivo "+(selD?selD.ano:"anterior")+".");
        return;
    }
    if (!rotPodeDeletarRotina(r)) { mostrarModalAviso("Sem permissão","Você não tem permissão para excluir esta rotina."); return; }
    var desc = rotTurmasTexto(r.turmas);
    mostrarModalConfirmacao("Excluir rotina","Excluir rotina de \""+desc+"\"?", async function() {
        rotLista = rotLista.filter(function(x){ return String(x.id)!==String(id); });
        if (String(rotIdAtual)===String(id)) { rotIdAtual=null; rotLimpar(); rotPreencherProfessorAuto(); }
        rotSalvarLocal(); rotRenderizarLista();
        await sbDeletarRotina(id);
    });
}

/* ════════════════════════════════════════════════════════════════
   MODAL DE VISUALIZAÇÃO
════════════════════════════════════════════════════════════════ */
function rotVisualizarId(id) {
    var r = rotLista.find(function(x){ return String(x.id)===String(id); });
    if (!r) return;
    _rotAtualVisualizando = r;
    _rotMontarModal(r);
    document.getElementById("modal-rot-viz").style.display = "flex";
}

function rotFecharModal() {
    document.getElementById("modal-rot-viz").style.display = "none";
    _rotAtualVisualizando = null;
}

function _rotMontarModal(r) {
    var periodo = r.dataIni ? formatarDataBr(r.dataIni)+(r.dataFim?" a "+formatarDataBr(r.dataFim):"") : "–";
    var escolaEl = document.getElementById("rviz-escola-nome");
    if (escolaEl) escolaEl.innerText = getNomeEscola();
    var turmasEl = document.getElementById("rviz-turma");
    if (turmasEl) turmasEl.innerHTML = rotTurmasBadges(r.turmas, false);
    document.getElementById("rviz-professor").innerText = r.professor||"–";
    document.getElementById("rviz-periodo").innerText   = periodo;
    document.getElementById("rviz-grade").innerHTML     = _buildGradeViz(r);
}

/* ── Visualização: grade ── */
function _buildGradeViz(r) {
    var html = "<table class='rot-viz-table'><thead><tr>"
             + "<th class='rot-viz-th-h'>Horário</th>";
    DIAS.forEach(function(d){ html+="<th>"+d.nome+"</th>"; });
    html += "</tr></thead><tbody>";
    var nLinhas = ROT_GRADE_NORMAL.length;

    ROT_GRADE_NORMAL.forEach(function(slot, rowIdx) {
        html += "<tr>";
        /* Horário */
        if (slot.tipo==="especial") {
            html += "<td class='rot-viz-horario rviz-h-int'><b>Int.</b><br><small>"+slot.h+"</small></td>";
        } else if (slot.tipo==="saida") {
            html += "<td class='rot-viz-horario rviz-h-saida'><b>Saída</b><br><small>"+slot.h+"</small></td>";
        } else {
            html += "<td class='rot-viz-horario'>"
                 + "<div class='rviz-hr-circle'>"+slot.label+"</div>"
                 + "<div class='rviz-hr-time'>"+slot.h+"</div></td>";
        }
        /* SEG–QUI */
        DIAS.filter(function(d){ return !d.sexta; }).forEach(function(dia) {
            if (slot.tipo==="especial") {
                html += "<td class='rot-viz-bloco-int'>☕ "+slot.h+" <small>("+slot.dur+")</small></td>";
            } else if (slot.tipo==="saida") {
                html += "<td class='rot-viz-bloco-saida'>🏠 "+slot.h+"</td>";
            } else {
                var cel = getCelula(r.celulas, slot.key, dia.col);
                html += "<td class='rot-viz-cel'>";
                if (cel.disc) html += "<div class='rot-viz-disc'>"+cel.disc+"</div>";
                if (cel.turma) html += "<div class='rot-viz-turmas-row'><span class='rot-turma-badge rot-turma-badge-sm'>"+_esc(cel.turma)+"</span></div>";
                if (cel.atv)  html += "<div class='rot-viz-atv'>"+cel.atv.replace(/\n/g,"<br>")+"</div>";
                if (!cel.disc&&!cel.atv) html += "<span style='color:#e2e8f0'>—</span>";
                html += "</td>";
            }
        });
        /* Sexta: rowspan */
        if (rowIdx===0) {
            html += "<td class='rot-viz-sexta-full' rowspan='"+nLinhas+"'>";
            ROT_GRADE_SEXTA.forEach(function(slot2) {
                if (slot2.tipo==="especial") {
                    html += "<div class='rviz-slot-int'>☕ Intervalo — "+slot2.dur+"<br><small>"+slot2.h+"</small></div>"; return;
                }
                if (slot2.tipo==="saida") {
                    html += "<div class='rviz-slot-saida'>🏠 Saída — "+slot2.h+"</div>"; return;
                }
                var cel = getCelula(r.celulas, slot2.key, 4);
                html += "<div class='rviz-slot-sexta'>"
                     + "<div class='rviz-slot-h'>"+slot2.label+" · "+slot2.h+"</div>";
                if (cel.disc) html += "<div class='rot-viz-disc'>"+cel.disc+"</div>";
                if (cel.turma) html += "<div class='rot-viz-turmas-row'><span class='rot-turma-badge rot-turma-badge-sm'>"+_esc(cel.turma)+"</span></div>";
                if (cel.atv)  html += "<div class='rot-viz-atv'>"+cel.atv.replace(/\n/g,"<br>")+"</div>";
                if (!cel.disc&&!cel.atv) html += "<span style='color:#cbd5e1;font-size:11px'>—</span>";
                html += "</div>";
            });
            html += "</td>";
        }
        html += "</tr>";
    });
    html += "</tbody></table>";
    return html;
}

/* ════════════════════════════════════════════════════════════════
   DUPLICAR ROTINA
════════════════════════════════════════════════════════════════ */
function rotDuplicarAtual() {
    if (!_rotAtualVisualizando) return;
    if (typeof alPodeEditar==="function" && !alPodeEditar()) {
        var selDup = typeof alGetAnoSelecionado==="function" ? alGetAnoSelecionado() : null;
        mostrarModalAviso("Modo histórico","Não é possível duplicar rotinas do Ano Letivo "+(selDup?selDup.ano:"anterior")+".");
        return;
    }
    if (!rotPodeEditarRotina(_rotAtualVisualizando)) { mostrarModalAviso("Sem permissão","Você não tem permissão para duplicar esta rotina."); return; }
    var copia = JSON.parse(JSON.stringify(_rotAtualVisualizando));
    copia.id = null;
    rotFecharModal();
    rotIdAtual = null;
    var turmasDisp = rotOrdenarTurmas([...new Set([
        ...rotNormalizarTurmas(copia.turmas||copia.turma),
        ..._rotExtrairTurmasDasCelulas(copia.celulas)
    ])]);
    rotSetTurmasSelecionadas(turmasDisp);
    document.getElementById("rot-professor").value = copia.professor||"";
    document.getElementById("rot-data-ini").value  = copia.dataIni  ||"";
    document.getElementById("rot-data-fim").value  = copia.dataFim  ||"";
    rotGerarTabela(copia.celulas);
    rotAtualizarBadgesTurmas();
    rotAtualizarHeader(rotTurmasTexto(turmasDisp)+" (cópia)", copia.professor);
    rotRenderizarLista();
    mostrarModalAviso("Rotina duplicada","Edite e clique em Salvar para criar a nova rotina.");
}

/* ════════════════════════════════════════════════════════════════
   PDF — A4 landscape, print correto
   REGRAS:
   • Turma vem de cada célula individualmente (cel.turma)
   • Cabeçalho mostra turmas disponíveis da rotina
   • window.print() chamado após document.close() com delay adequado
   • Sem Font Awesome (não carrega em janela isolada)
   • table-layout:fixed com larguras absolutas em px
════════════════════════════════════════════════════════════════ */
function rotImprimirModal() {
    if (!_rotAtualVisualizando) return;
    var r      = _rotAtualVisualizando;
    var escola = getNomeEscola();
    var turmas = rotNormalizarTurmas(r.turmas||r.turma);
    var prof   = (document.getElementById("rviz-professor")||{}).innerText || r.professor || "";
    var per    = (document.getElementById("rviz-periodo")||{}).innerText || "";


    /* Logo da escola em base64 — sempre disponível offline e na impressão */
    var LOGO_B64 = "data:image/png;base64,";

    var COR_COMP = {
        "PORTUGUÊS":"#1E40AF","MATEMÁTICA":"#DC2626","CIÊNCIAS":"#7C3AED",
        "GEOGRAFIA":"#0891B2","HISTÓRIA":"#B45309","ARTE":"#2563EB",
        "EDUCAÇÃO FÍSICA":"#EA580C","ENSINO RELIGIOSO":"#059669",
        "EDUCAÇÃO FINANCEIRA":"#0D9488","EDUCAÇÃO AMBIENTAL":"#16A34A"
    };

    /* ── Coluna horário ── */
    function bHor(slot) {
        if (slot.tipo==="especial")
            return "<td class='pt pt-int'>Intervalo<br><span class='psub'>"+slot.h+" · "+slot.dur+"</span></td>";
        if (slot.tipo==="saida")
            return "<td class='pt pt-saida'>Saída<br><span class='psub'>"+slot.h+"</span></td>";
        /* slot.label já é "1º" — hora em linha única */
        return "<td class='pt'><div class='pc'>"+slot.label+"</div><div class='ph'>"+slot.h+"</div></td>";
    }

    /* ── Célula de conteúdo SEG–QUI ── */
    function bCel(slot, colIdx) {
        if (slot.tipo==="especial") return "<td class='pd pd-int'>"+slot.h+"</td>";
        if (slot.tipo==="saida")   return "<td class='pd pd-saida'>"+slot.h+"</td>";
        var cel = getCelula(r.celulas, slot.key, colIdx);
        if (!cel.disc&&!cel.atv&&!cel.turma) return "<td class='pd pd-vazio'></td>";
        var cor = COR_COMP[cel.disc]||"#1E40AF";
        var linhaTurma = "";
        if (cel.disc || cel.turma) {
            linhaTurma = "<div class='pcomp-row' style='border-bottom:1.5px solid "+cor+"30;margin-bottom:3px;padding-bottom:3px;'>"
                + (cel.disc ? "<span class='pdisc' style='color:"+cor+"'>"+_esc(cel.disc)+"</span>" : "")
                + (cel.disc && cel.turma ? "<span class='psep'>/</span>" : "")
                + (cel.turma ? "<span class='pturma'>"+_esc(cel.turma)+"</span>" : "")
                + "</div>";
        }
        return "<td class='pd'>"
             + linhaTurma
             + (cel.atv  ? "<div class='patv'>"+cel.atv.replace(/\n/g,"<br>")+"</div>" : "")
             + "</td>";
    }

    /* ── Slot sexta ── */
    function bSex(slot) {
        if (slot.tipo==="especial")
            return "<div class='pfri pfri-int'>Intervalo "+slot.dur+"<br><small>"+slot.h+"</small></div>";
        if (slot.tipo==="saida")
            return "<div class='pfri pfri-saida'>Saída — "+slot.h+"</div>";
        var cel = getCelula(r.celulas, slot.key, 4);
        var cor = COR_COMP[cel.disc]||"#3B82F6";
        var linhaTurmaS = "";
        if (cel.disc || cel.turma) {
            linhaTurmaS = "<div class='pcomp-row' style='border-bottom:1.5px solid "+cor+"30;margin-bottom:3px;padding-bottom:3px;'>"
                + (cel.disc ? "<span class='pdisc' style='color:"+cor+"'>"+_esc(cel.disc)+"</span>" : "")
                + (cel.disc && cel.turma ? "<span class='psep'>/</span>" : "")
                + (cel.turma ? "<span class='pturma'>"+_esc(cel.turma)+"</span>" : "")
                + "</div>";
        }
        return "<div class='pfri'>"
             /* label e horário SEMPRE visíveis em todos os slots da sexta */
             + "<div class='pfri-h'>"+slot.label+" · "+slot.h+"</div>"
             + linhaTurmaS
             + (cel.atv  ? "<div class='patv'>"+cel.atv.replace(/\n/g,"<br>")+"</div>" : "")
             + (!cel.disc&&!cel.turma&&!cel.atv?"<div style='color:#cbd5e1'>—</div>":"")
             + "</div>";
    }

    /* ── Cabeçalho: turmas disponíveis da rotina ── */
    var cabTurmas = turmas.length
        ? turmas.map(function(t){ return "<span class='htb'>"+_esc(t)+"</span>"; }).join("")
        : "<span class='htb'>"+_esc(escola)+"</span>";

    /* ── Larguras inteligentes por coluna (±15px) ── */
    var BASE_CD = 183; /* largura base de cada coluna de dia */
    var colWidths = [0,1,2,3].map(function(col){
        /* conta o número de células com conteúdo nessa coluna */
        var filled = 0;
        ROT_GRADE_NORMAL.forEach(function(slot){
            if(slot.tipo!=="aula") return;
            var cel = getCelula(r.celulas, slot.key, col);
            if(cel.disc||cel.atv||cel.turma) filled++;
        });
        return filled; /* 0-5 tipicamente */
    });
    var maxFill = Math.max.apply(null, colWidths) || 1;
    /* variação de -15px (vazia) a +15px (mais cheia), em relação à base */
    var adjustedWidths = colWidths.map(function(f){
        var ratio = f / maxFill; /* 0..1 */
        var adj = Math.round((ratio - 0.5) * 30); /* -15..+15 */
        return BASE_CD + adj;
    });
    /* garantir que a soma dos 4 dias fique consistente (máx desvio ±60px no total) */
    var totalAdj = adjustedWidths.reduce(function(a,b){return a+b;},0);
    var targetTotal = BASE_CD * 4;
    var diff = targetTotal - totalAdj;
    adjustedWidths[2] += diff; /* compensar na quarta (coluna que tende a estar vazia) */
    /* largura da sexta baseada no restante disponível */
    var totalTable = 1020;
    var horCol = 74;
    var sextaWidth = totalTable - horCol - adjustedWidths.reduce(function(a,b){return a+b;},0) - 5;
    sextaWidth = Math.max(120, Math.min(160, sextaWidth));

    /* ── Gera colgroup dinâmico ── */
    var colgroup = "<colgroup>"
        +"<col style='width:"+horCol+"px'>"
        +adjustedWidths.map(function(w){ return "<col style='width:"+w+"px'>"; }).join("")
        +"<col style='width:"+sextaWidth+"px'>"
        +"</colgroup>";

    /* ── Linhas ── */
    var nL = ROT_GRADE_NORMAL.length;
    var rows = "";
    ROT_GRADE_NORMAL.forEach(function(slot, idx) {
        /* altura mínima da linha: aulas normais têm mais espaço, especiais menos */
        var rowMinH = slot.tipo==="aula" ? 68 : 32;
        rows += "<tr style='height:"+rowMinH+"px'>"+bHor(slot);
        [0,1,2,3].forEach(function(col){ rows += bCel(slot,col); });
        if (idx===0) {
            rows += "<td class='pfri-col' rowspan='"+nL+"'>";
            ROT_GRADE_SEXTA.forEach(function(s){ rows += bSex(s); });
            rows += "</td>";
        }
        rows += "</tr>";
    });

    /* ── CSS — larguras absolutas em px para print estável ── */
    var css = [
        "*{margin:0;padding:0;box-sizing:border-box;font-family:'Segoe UI',Helvetica,Arial,sans-serif;}",
        "body{background:#f8fafc;padding:12px;display:flex;justify-content:center;}",
        ".wrap{width:1060px;background:#fff;border-radius:10px;padding:16px 20px;",
        "       border:1px solid #e2e8f0;box-shadow:0 4px 20px rgba(0,0,0,.08);}",
        /* ── Cabeçalho ── */
        ".hdr{display:flex;align-items:flex-start;justify-content:space-between;",
        "      border-bottom:2.5px solid #2563EB;padding-bottom:12px;margin-bottom:14px;gap:12px;}",
        ".hdr-l{flex:1;min-width:0;}",
        ".hdr-escola{font-size:16px;font-weight:800;color:#1E40AF;margin-bottom:2px;}",
        ".hdr-sub{font-size:9px;color:#94a3b8;text-transform:uppercase;letter-spacing:.7px;font-weight:600;margin-bottom:7px;}",
        ".hdr-turmas{display:flex;flex-wrap:wrap;gap:4px;}",
        ".htb{background:#1E40AF;color:#fff;font-size:10px;font-weight:700;padding:3px 9px;border-radius:20px;}",
        ".hdr-r{display:flex;flex-direction:column;gap:6px;border-left:1px solid #e2e8f0;padding-left:14px;min-width:170px;}",
        /* logo */
        ".hdr-logo-wrap{flex-shrink:0;width:70px;height:70px;display:flex;align-items:center;justify-content:center;}",
        ".hdr-logo{width:68px;height:68px;object-fit:contain;}",
        ".hm{display:flex;align-items:center;gap:7px;}",
        ".hm-ico{width:22px;height:22px;background:#eff6ff;color:#2563EB;border-radius:5px;",
        "         display:flex;align-items:center;justify-content:center;font-size:11px;flex-shrink:0;}",
        ".hm-lbl{font-size:9px;color:#94a3b8;font-weight:500;display:block;}",
        ".hm-val{font-size:11px;color:#1e293b;font-weight:700;display:block;}",
        /* ── Tabela: larguras fixas absolutas ── */
        "table{width:1020px;border-collapse:separate;border-spacing:1px;",
        "       background:#d1d5db;border-radius:8px;overflow:hidden;table-layout:fixed;}",
        /* larguras injetadas via colgroup dinâmico — sem classes estáticas aqui */
        "thead th{background:linear-gradient(160deg,#1E40AF 0%,#3B82F6 100%);color:#fff;padding:7px 5px;font-size:9px;font-weight:700;",
        "           text-align:center;letter-spacing:.3px;text-transform:uppercase;}",
        "thead th.thf{background:linear-gradient(160deg,#2563EB 0%,#60A5FA 100%);}",
        /* ── Linha: height mínimo definido inline no <tr> para acompanhar maior célula ── */
        "tr{vertical-align:stretch;}",
        /* ── Horário ── */
        ".pt{background:#fff;text-align:center;vertical-align:middle;padding:5px 3px;}",
        ".pc{width:24px;height:24px;border:2px solid #1E40AF;color:#1E40AF;border-radius:50%;",
        "     display:flex;align-items:center;justify-content:center;margin:0 auto 3px;",
        "     font-size:9.5px;font-weight:800;}",
        ".ph{font-size:8.5px;color:#94a3b8;line-height:1.3;text-align:center;}",
        ".psub{font-size:8px;color:#94a3b8;}",
        ".pt-int{background:#fef9ec!important;color:#92400e;font-size:9px;font-weight:700;vertical-align:middle;}",
        ".pt-saida{background:#f0fdf4!important;color:#166534;font-size:9px;font-weight:700;vertical-align:middle;}",
        /* ── Células SEG-QUI: sem min-height, crescem com conteúdo e puxam a linha ── */
        ".pd{background:#fff;padding:8px 9px;vertical-align:top;word-wrap:break-word;overflow-wrap:break-word;}",
        ".pd-int{background:#fef9ec!important;text-align:center;vertical-align:middle;",
        "         font-size:9px;color:#92400e;font-weight:600;}",
        ".pd-saida{background:#f0fdf4!important;text-align:center;vertical-align:middle;",
        "           font-size:9px;color:#166534;font-weight:600;}",
        ".pd-vazio{background:#fafafa!important;}",
        ".patv{font-size:9.5px;color:#475569;line-height:1.4;}",
        ".pcomp-row{display:flex;align-items:baseline;flex-wrap:wrap;gap:4px;}",
        ".pdisc{font-size:9.5px;font-weight:800;text-transform:uppercase;letter-spacing:.2px;}",
        ".psep{font-size:9.5px;color:#94a3b8;font-weight:400;}",
        ".pturma{font-size:9px;font-weight:700;color:#6d28d9;white-space:nowrap;}",
        /* ── Sexta: acompanha altura EXTERNA da linha, fluxo interno independente ──  */
        /* height:100% faz a td ocupar toda a linha sem alterar o fluxo dos pfri internos */
        ".pfri-col{background:#fff!important;vertical-align:top;padding:0;",
        "           border-left:2px solid #bfdbfe!important;height:100%;}",
        /* pfri: sem min-height forçado — cada slot tem seu próprio tamanho natural */
        ".pfri{padding:8px 10px;border-bottom:1px dashed #e2e8f0;}",
        ".pfri:last-child{border-bottom:none;}",
        ".pfri-h{font-size:8.5px;color:#94a3b8;font-weight:600;text-transform:uppercase;margin-bottom:3px;}",
        ".pfri-int{display:flex;flex-direction:column;justify-content:center;padding:8px 10px;",
        "           background:#fef9ec!important;color:#92400e;font-size:9px;font-weight:700;}",
        ".pfri-int small{font-size:8px;opacity:.75;}",
        ".pfri-saida{display:flex;align-items:center;padding:8px 10px;",
        "             background:#f0fdf4!important;color:#166534;font-size:9px;font-weight:700;}",
        /* ── Print ── */
        "@media print{",
        "  body{background:#fff!important;padding:0!important;display:block!important;}",
        "  .wrap{width:100%!important;box-shadow:none!important;border:none!important;",
        "         border-radius:0!important;padding:6px 10px!important;}",
        "  table{width:100%!important;}",
        "  *{-webkit-print-color-adjust:exact!important;print-color-adjust:exact!important;}",
        "  @page{size:A4 landscape;margin:6mm;}",
        "}"
    ].join("");

    var htmlFinal = "<!DOCTYPE html><html lang='pt-BR'><head>"
        + "<meta charset='UTF-8'>"
        + "<title>Rotina — "+_esc(turmas.join(" / "))+"</title>"
        + "<style>"+css+"</style>"
        + "</head><body>"
        + "<div class='wrap'>"
        /* cabeçalho com logo */
        + "<div class='hdr'>"
        +   "<div class='hdr-logo-wrap'>"
        +     "<img src='"+LOGO_B64+"' class='hdr-logo' alt='Logo'>"
        +   "</div>"
        +   "<div class='hdr-l'>"
        +     "<div class='hdr-escola'>"+_esc(escola)+"</div>"
        +     "<div class='hdr-sub'>Rotina Semanal de Atividades</div>"
        +     "<div class='hdr-turmas'>"+cabTurmas+"</div>"
        +   "</div>"
        +   "<div class='hdr-r'>"
        +     "<div class='hm'><div class='hm-ico'>&#128100;</div>"
        +       "<div><span class='hm-lbl'>Professor(a)</span><span class='hm-val'>"+_esc(prof)+"</span></div></div>"
        +     "<div class='hm'><div class='hm-ico'>&#128197;</div>"
        +       "<div><span class='hm-lbl'>Período</span><span class='hm-val'>"+_esc(per)+"</span></div></div>"
        +   "</div>"
        + "</div>"
        /* tabela */
        + "<table>"
        +   colgroup
        +   "<thead><tr>"
        +     "<th>Horário</th>"
        +     "<th>Segunda</th><th>Ter&ccedil;a</th><th>Quarta</th><th>Quinta</th>"
        +     "<th class='thf'>Sexta</th>"
        +   "</tr></thead>"
        +   "<tbody>"+rows+"</tbody>"
        + "</table>"
        + "</div>"
        /* Script de impressão — usa setTimeout para garantir render completo */
        + "<script>"
        + "window.addEventListener('load',function(){"
        + "  setTimeout(function(){window.print();},400);"
        + "});"
        + "<\/script>"
        + "</body></html>";

    mostrarLoadingSimples("Gerando PDF...");
    var w = window.open("","_blank","width=1200,height=860,menubar=yes,toolbar=yes");
    if (!w) {
        ocultarLoadingSimples();
        mostrarModalAviso("Bloqueado","O navegador bloqueou a janela popup. Permita popups para este site e tente novamente.");
        return;
    }
    w.document.open();
    w.document.write(htmlFinal);
    w.document.close();
    setTimeout(function(){ ocultarLoadingSimples(); }, 600);
}
